          "rules": [
            "[orderId] != ''",
            "[customerId] != ''",
            "[kycApproved] == false",
            "[rejectionReason] != ''"
          ],
          "onValid": {
            "payload": {
              "orderId": "[orderId]",
              "customerId": "[customerId]",
              "orderStatus": "cancelled",
              "cancellationReason": "[rejectionReason]",
              "cleanlyEnded": true
            }
          },
          "onInvalid": {
            "payload": {
              "orderStatus": "cancelled",
              "cancellationReason": "KYC rejected.",
              "cleanlyEnded": true
            }
          }
        },
