                "spawns": [
                  "cancel_order"
                ]
              }
            },
            "fulfill_order": {
              "rule": "0x3791B56be73b84f1C1d24E614A36DA8792732701"
            },
            "cancel_order": {
              "rule": "0xC4ac4AA4C638ED0a0cceeAbF65a5088eB24aa26f"
            }
          },
          "address": "0xd5b21573A7401C244C44a773d5eA6dADca71E3e2"
        }
      ]
    }
  ]
}

