                  "from": [
                    {
                      "node": "verify_customer_data",
                      "when": "valid"
                    },
                    {
                      "node": "verify_identity_document",
                      "when": "valid"
                    },
                    {
                      "node": "screen_pep_sanctions",
                      "when": "valid"
                    }
                  ]
                }
              },
              "onInvalid": {
                "spawns": [
                  "customer_rejected"
                ]
              }
            },
            "verify_customer_data": {
              "rule": "0xf195259D5DB24611967b4dEb937977D2d967cf4A",
              "onInvalid": {
                "spawns": [
                  "customer_rejected"
                ]
              }
            },
            "verify_identity_document": {
              "rule": "0xe36d89e7E0BBA2E2F2A225109f3fA29967285296",
              "onInvalid": {
                "spawns": [
                  "customer_rejected"
                ]
              }
            },
            "screen_pep_sanctions": {
              "rule": "0xd3d938D361A6519dB2dD7850C9b2e8Ac84ADB259",
              "onInvalid": {
                "spawns": [
                  "customer_rejected"
                ]
              }
            },
            "analyze_information_documents": {
              "rule": "0xe2D7a8E5a834b22F77A2BC940592C237a5df24BA",
              "onValid": {
                "spawns": [
                  "live_verification"
                ]
              },
              "onInvalid": {
                "spawns": [
                  "customer_rejected"
                ]
              }
            },
            "live_verification": {
              "rule": "0x3D50434EC3b93aAD44393C9CfB14E6d82298c822",
              "onValid": {
                "spawns": [
                  "customer_accepted"
                ]
              },
              "onInvalid": {
                "spawns": [
                  "customer_rejected"
                ]
              }
            },
            "customer_accepted": {
              "rule": "0x006D8E5337D5F893BC1295Cc5e84fae7910e8FD2",
              "onValid": {
                "spawns": [
                  "notify_order_kyc_valid"
                ]
              },
              "onInvalid": {
                "spawns": [
                  "customer_rejected"
                ]
              }
            },
            "customer_rejected": {
