                  "notify_order_kyc_invalid"
                ]
              },
              "onInvalid": {
                "spawns": [
                  "notify_order_kyc_invalid"
                ]
              }
            },
            "notify_order_kyc_valid": {
              "rule": "0x73C703198fF53dd49391a7935f1bd91986401228"
            },
            "notify_order_kyc_invalid": {
              "rule": "0x09478D772Aac6D36fEEE606035e8024027884540"
            }
          },
          "address": "0x28aCEd6B0e82FBce3be0c818eF3aE1A699065682"
        }
      ]
    }
  ]
}

